;
	lda     #$00
	sta     _thousands_step
;
; if(ten_thousands_step == 9){
;
	lda     _ten_thousands_step
	cmp     #$09
	bne     L1E0E
;
; ten_thousands_step = 0;
;
	lda     #$00
	sta     _ten_thousands_step
;
; } else {
;
	rts
;
; ten_thousands_step++;
